const input = $input.first()?.json || {};
const body = input && typeof input === 'object' && input.body && typeof input.body === 'object' ? input.body : input;

function toText(v) {
  if (v == null) return '';
  if (Array.isArray(v)) {
    return v.map((x) => {
      if (x == null) return '';
      if (typeof x === 'string') return x;
      if (typeof x === 'number') return String(x);
      if (typeof x === 'object') return x.text ?? x.name ?? x.value ?? '';
      return String(x);
    }).filter(Boolean).join('\n').trim();
  }
  if (typeof v === 'object') return String(v.text ?? v.value ?? v.name ?? '').trim();
  return String(v).trim();
}

function toNumber(v) {
  if (v == null) return NaN;
  if (typeof v === 'number' && Number.isFinite(v)) return v;
  const s = toText(v);
  if (!s) return NaN;
  const direct = Number(s);
  if (Number.isFinite(direct)) return direct;
  const m = s.match(/(\d+(\.\d+)?)/);
  if (m) {
    const n = Number(m[1]);
    if (Number.isFinite(n)) return n;
  }
  return NaN;
}

function parseDurationToSec(v, fallback = 32) {
  if (v == null) return fallback;
  if (typeof v === 'number' && Number.isFinite(v)) return Math.max(1, Math.round(v));
  const s0 = toText(v);
  if (!s0) return fallback;
  const s = s0.trim();
  if (/^\d{1,2}:\d{2}(:\d{2})?$/.test(s)) {
    const parts = s.split(':').map((x) => parseInt(x, 10));
    if (parts.some((n) => !Number.isFinite(n))) return fallback;
    if (parts.length === 2) return parts[0] * 60 + parts[1];
    if (parts.length === 3) return parts[0] * 3600 + parts[1] * 60 + parts[2];
  }
  const minMatch = s.match(/(\d+)\s*(分|分钟|min|mins|minute|minutes)/i);
  const secMatch = s.match(/(\d+)\s*(秒|s|sec|secs|second|seconds)/i);
  if (minMatch || secMatch) {
    const mins = minMatch ? parseInt(minMatch[1], 10) : 0;
    const secs = secMatch ? parseInt(secMatch[1], 10) : 0;
    const total = mins * 60 + secs;
    return total > 0 ? total : fallback;
  }
  const n = toNumber(s);
  if (Number.isFinite(n) && n > 0) return Math.max(1, Math.round(n));
  return fallback;
}

const task_id = toText(body.task_id) || toText(body.taskId) || toText(body.record_id) || toText(body.recordId) || '';
const callback_url = toText(body.callback_url) || toText(body.callbackUrl) || '';
const admin_token = toText(body.admin_token) || toText(body.adminToken) || '';
const pipeline_key = toText(body.pipeline_key) || toText(body.pipelineKey) || 'skeleton_video';
const api_key = toText(body.api_key) || toText(body.apiKey);
const app_id = toText(body.app_id) || toText(body.appId);
const app_secret = toText(body.app_secret) || toText(body.appSecret);
const workflow_id = toText(body.workflow_id) || toText(body.workflowId);
const workflow_name = toText(body.workflow_name) || toText(body.workflowName);

const productDesc = toText(body.product_selling_points || body.productSellingPoints || body.product_description || body.productDescription || body['产品卖点'] || body['产品描述'] || '');
const productName = toText(body.product_name || body.productName || body['产品名称'] || '');
const language = toText(body.target_language || body.videoLanguage || body.language || body['视频语言'] || 'Chinese');
const presenterMode = toText(body.presenterMode || body['人物模式'] || 'talking_head');

const durationRaw = body.duration_sec ?? body.durationSec ?? body.duration ?? body.videoDuration ?? body['时长'] ?? body['视频时长'] ?? body['时长(秒)'];
const durationSec = parseDurationToSec(durationRaw, 32);
const segSecondsRaw = body.seg_seconds ?? body.segSeconds ?? body['分段时长'] ?? 8;
const segSeconds = Math.max(1, Math.round(toNumber(segSecondsRaw) || 8));
const nSegments = Math.max(1, Math.ceil(durationSec / segSeconds));

const refScript = toText(body.script || body.script_content || body.scriptContent || body.refScript || body['参考脚本'] || body['参考爆款脚本'] || body['爆款脚本'] || '');
const personDesc = toText(body.person_desc || body.personDesc || body['达人特征'] || body['达人特征描述'] || body['人物特征'] || '');
const viralScriptSummaryRaw = toText(body.viral_script_summary || body.viralScriptSummary || body['爆款脚本总结'] || body['爆款脚本总结JSON'] || body['爆款脚本拆解'] || body['爆款总结'] || '');

let viralScriptSummary = null;
if (viralScriptSummaryRaw) {
  const s = viralScriptSummaryRaw.trim();
  if (s.startsWith('{') || s.startsWith('[')) {
    try {
      viralScriptSummary = JSON.parse(s);
    } catch {
      viralScriptSummary = null;
    }
  }
}

return [{
  ...input,
  ...body,
  task_id,
  record_id: task_id,
  callback_url,
  admin_token,
  pipeline_key,
  api_key,
  app_id,
  app_secret,
  workflow_id,
  workflow_name,
  productName,
  productDesc,
  personDesc,
  presenterMode,
  language,
  durationSec,
  segSeconds,
  nSegments,
  refScript,
  viralScriptSummaryRaw,
  viralScriptSummary,
}];

function stripFences(s) { return String(s || '').trim().replace(/^```[a-zA-Z]*\n?/, '').replace(/```$/, '').trim(); }
function safeParse(s) { try { return JSON.parse(s); } catch { return null; } }
function pickRawText(in0) {
  if (!in0) return '';
  if (typeof in0 === 'object' && in0.shots && Array.isArray(in0.shots)) return in0;
  return in0.output || in0.text || in0.response || in0?.candidates?.[0]?.content?.parts?.[0]?.text || '';
}
function extractFirstJsonObject(str) {
  const s = String(str || '');
  const i = s.indexOf('{'), j = s.lastIndexOf('}');
  return (i < 0 || j <= i) ? null : s.slice(i, j + 1);
}
function toBool(v) {
  const t = String(v == null ? '' : v).trim().toLowerCase();
  if (['1','true','yes','y','是','有'].includes(t)) return true;
  if (['0','false','no','n','否','无'].includes(t)) return false;
  return null;
}
function toText(v) {
  if (v == null) return '';
  if (Array.isArray(v)) return v.map((x) => toText(x)).filter(Boolean).join('\n').trim();
  if (typeof v === 'object') return String(v.text ?? v.value ?? v.name ?? '').trim();
  return String(v).trim();
}

const in0 = $input.first()?.json || {};
let raw = pickRawText(in0);
let obj = raw && typeof raw === 'object' && Array.isArray(raw.shots) ? raw : safeParse(extractFirstJsonObject(stripFences(raw)));
if (!obj || !Array.isArray(obj.shots)) throw new Error('JSON Parse failed or no shots array.');

const root = $('标准化输入').first()?.json || {};
const AI达人 = toText(root['AI达人'] || root.ai_creator || root.creatorName || '');
const 产品名称 = toText(root.productName || root.product_name || root['产品名称'] || '');
const task_id = toText(root.task_id || root.record_id || root.recordId || '');
const callback_url = toText(root.callback_url || root.callbackUrl || '');
const admin_token = toText(root.admin_token || root.adminToken || '');
const pipeline_key = toText(root.pipeline_key || root.pipelineKey || 'skeleton_video');
const workflow_id = toText(root.workflow_id || root.workflowId || '');
const workflow_name = toText(root.workflow_name || root.workflowName || '');

const shots = obj.shots.map((s, idx) => ({
  idx: s.shot_number || s.idx || s.order || idx + 1,
  shot_number: s.shot_number || idx + 1,
  timestamp: s.timestamp || '',
  time_range: s.timestamp || s.time_range || s.timeRange || '',
  duration_seconds: s.duration_seconds || s.duration || 8,
  duration: s.duration_seconds || s.duration || 8,
  voiceover: String(s.voiceover || s.speech || s.text || ''),
  action: String(s.action || ''),
  first_frame: String(s.first_frame || s.image_prompt || '').replace(/[\r\n]+/g, ' ').trim(),
  video_prompt: String(s.video_prompt || s.videoPrompt || '').replace(/[\r\n]+/g, ' ').trim(),
  has_product: toBool(s['是否有产品'] ?? s.has_product ?? s.hasProduct),
  '是否有产品': toBool(s['是否有产品'] ?? s.has_product ?? s.hasProduct),
  AI达人,
  产品名称,
}));

return [{ json: {
  task_id,
  callback_url,
  admin_token,
  pipeline_key,
  workflow_id,
  workflow_name,
  total_shots: shots.length,
  shots,
}}];

